"""
Kenny Integration Module for Swarm Intelligence

This module integrates swarm intelligence capabilities with Kenny's
main AI system, providing enhanced optimization and coordination
for GUI automation tasks.
"""

import numpy as np
import logging
import time
from typing import Dict, List, Any, Optional, Callable, Tuple
from dataclasses import dataclass
import asyncio

from .swarm_coordinator import SwarmIntelligenceCoordinator, SwarmConfiguration
from .multi_agent import MultiAgentCoordinator, create_multi_agent_system
from .metrics import SwarmMetrics
